-- Create "pos_permissions" table
CREATE TABLE "pos_permissions" ("id" uuid NOT NULL, "permission_code" character varying NOT NULL, "name" character varying NOT NULL, "module" character varying NOT NULL, "action" character varying NOT NULL, "resource" character varying NULL, "description" text NULL, "created_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "pos_permissions_permission_code_key" to table: "pos_permissions"
CREATE UNIQUE INDEX "pos_permissions_permission_code_key" ON "pos_permissions" ("permission_code");
-- Create index "pospermission_action" to table: "pos_permissions"
CREATE INDEX "pospermission_action" ON "pos_permissions" ("action");
-- Create index "pospermission_module" to table: "pos_permissions"
CREATE INDEX "pospermission_module" ON "pos_permissions" ("module");
-- Create index "pospermission_module_action" to table: "pos_permissions"
CREATE INDEX "pospermission_module_action" ON "pos_permissions" ("module", "action");
-- Create index "pospermission_permission_code" to table: "pos_permissions"
CREATE UNIQUE INDEX "pospermission_permission_code" ON "pos_permissions" ("permission_code");
-- Create "rate_limit_configs" table
CREATE TABLE "rate_limit_configs" ("id" uuid NOT NULL, "service_name" character varying NOT NULL, "key_type" character varying NOT NULL, "endpoint_pattern" character varying NOT NULL DEFAULT '*', "requests_per_window" bigint NOT NULL DEFAULT 60, "window_seconds" bigint NOT NULL DEFAULT 60, "burst_multiplier" double precision NOT NULL DEFAULT 1.5, "is_active" boolean NOT NULL DEFAULT true, "description" character varying NULL, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "ratelimitconfig_is_active" to table: "rate_limit_configs"
CREATE INDEX "ratelimitconfig_is_active" ON "rate_limit_configs" ("is_active");
-- Create index "ratelimitconfig_service_name" to table: "rate_limit_configs"
CREATE INDEX "ratelimitconfig_service_name" ON "rate_limit_configs" ("service_name");
-- Create index "ratelimitconfig_service_name_key_type_endpoint_pattern" to table: "rate_limit_configs"
CREATE UNIQUE INDEX "ratelimitconfig_service_name_key_type_endpoint_pattern" ON "rate_limit_configs" ("service_name", "key_type", "endpoint_pattern");
-- Create "service_configs" table
CREATE TABLE "service_configs" ("id" uuid NOT NULL, "tenant_id" uuid NULL, "config_key" character varying NOT NULL, "config_value" text NOT NULL, "config_type" character varying NOT NULL DEFAULT 'string', "description" character varying NULL, "is_secret" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "serviceconfig_config_key" to table: "service_configs"
CREATE INDEX "serviceconfig_config_key" ON "service_configs" ("config_key");
-- Create index "serviceconfig_tenant_id_config_key" to table: "service_configs"
CREATE UNIQUE INDEX "serviceconfig_tenant_id_config_key" ON "service_configs" ("tenant_id", "config_key");
-- Create "pos_role_v2s" table
CREATE TABLE "pos_role_v2s" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "role_code" character varying NOT NULL, "name" character varying NOT NULL, "description" text NULL, "is_system_role" boolean NOT NULL DEFAULT false, "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, PRIMARY KEY ("id"));
-- Create index "posrolev2_is_system_role" to table: "pos_role_v2s"
CREATE INDEX "posrolev2_is_system_role" ON "pos_role_v2s" ("is_system_role");
-- Create index "posrolev2_tenant_id" to table: "pos_role_v2s"
CREATE INDEX "posrolev2_tenant_id" ON "pos_role_v2s" ("tenant_id");
-- Create index "posrolev2_tenant_id_role_code" to table: "pos_role_v2s"
CREATE UNIQUE INDEX "posrolev2_tenant_id_role_code" ON "pos_role_v2s" ("tenant_id", "role_code");
-- Create "pos_role_permissions" table
CREATE TABLE "pos_role_permissions" ("id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY, "role_id" uuid NOT NULL, "permission_id" uuid NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "pos_role_permissions_pos_permissions_permission" FOREIGN KEY ("permission_id") REFERENCES "pos_permissions" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "pos_role_permissions_pos_role_v2s_role" FOREIGN KEY ("role_id") REFERENCES "pos_role_v2s" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "posrolepermission_permission_id" to table: "pos_role_permissions"
CREATE INDEX "posrolepermission_permission_id" ON "pos_role_permissions" ("permission_id");
-- Create index "posrolepermission_role_id" to table: "pos_role_permissions"
CREATE INDEX "posrolepermission_role_id" ON "pos_role_permissions" ("role_id");
-- Create index "posrolepermission_role_id_permission_id" to table: "pos_role_permissions"
CREATE UNIQUE INDEX "posrolepermission_role_id_permission_id" ON "pos_role_permissions" ("role_id", "permission_id");
-- Create "pos_user_role_assignments" table
CREATE TABLE "pos_user_role_assignments" ("id" uuid NOT NULL, "tenant_id" uuid NOT NULL, "assigned_by" uuid NOT NULL, "assigned_at" timestamptz NOT NULL, "expires_at" timestamptz NULL, "pos_role_v2_user_assignments" uuid NULL, "user_id" uuid NOT NULL, "role_id" uuid NOT NULL, PRIMARY KEY ("id"), CONSTRAINT "pos_user_role_assignments_pos_role_v2s_role" FOREIGN KEY ("role_id") REFERENCES "pos_role_v2s" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, CONSTRAINT "pos_user_role_assignments_pos_role_v2s_user_assignments" FOREIGN KEY ("pos_role_v2_user_assignments") REFERENCES "pos_role_v2s" ("id") ON UPDATE NO ACTION ON DELETE SET NULL, CONSTRAINT "pos_user_role_assignments_users_user" FOREIGN KEY ("user_id") REFERENCES "users" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION);
-- Create index "posuserroleassignment_expires_at" to table: "pos_user_role_assignments"
CREATE INDEX "posuserroleassignment_expires_at" ON "pos_user_role_assignments" ("expires_at");
-- Create index "posuserroleassignment_role_id" to table: "pos_user_role_assignments"
CREATE INDEX "posuserroleassignment_role_id" ON "pos_user_role_assignments" ("role_id");
-- Create index "posuserroleassignment_tenant_id" to table: "pos_user_role_assignments"
CREATE INDEX "posuserroleassignment_tenant_id" ON "pos_user_role_assignments" ("tenant_id");
-- Create index "posuserroleassignment_tenant_id_user_id_role_id" to table: "pos_user_role_assignments"
CREATE UNIQUE INDEX "posuserroleassignment_tenant_id_user_id_role_id" ON "pos_user_role_assignments" ("tenant_id", "user_id", "role_id");
-- Create index "posuserroleassignment_user_id" to table: "pos_user_role_assignments"
CREATE INDEX "posuserroleassignment_user_id" ON "pos_user_role_assignments" ("user_id");
